import{_ as t,o as i,c as a,ah as n}from"./chunks/framework.BxsLfmww.js";const m=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"de/faq.md","filePath":"de/faq.md"}'),s={name:"de/faq.md"};function l(r,e,d,h,o,c){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="welche-shells-werden-unterstutzt" tabindex="-1">Welche Shells werden unterstützt? <a class="header-anchor" href="#welche-shells-werden-unterstutzt" aria-label="Permalink to &quot;Welche Shells werden unterstützt?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Shell</th><th>Status</th></tr></thead><tbody><tr><td>Fish</td><td>Vollständig unterstützt und getestet</td></tr><tr><td>PowerShell</td><td>Unterstützt und getestet (5.1 + 7)</td></tr><tr><td>Zsh</td><td>Unterstützt, noch nicht getestet</td></tr><tr><td>Bash, Nushell</td><td>Noch nicht implementiert</td></tr></tbody></table><h2 id="wie-unterscheidet-sich-das-von-shell-aliasen-in-meinen-dotfiles" tabindex="-1">Wie unterscheidet sich das von Shell-Aliasen in meinen Dotfiles? <a class="header-anchor" href="#wie-unterscheidet-sich-das-von-shell-aliasen-in-meinen-dotfiles" aria-label="Permalink to &quot;Wie unterscheidet sich das von Shell-Aliasen in meinen Dotfiles?&quot;">​</a></h2><p>Traditionelle Aliase sind statisch — einmal in <code>.bashrc</code> oder <code>.zshrc</code> definiert. amoxide bietet zusätzlich:</p><ul><li><strong>Profile</strong> — benannte Gruppen, die ohne Dateien zu bearbeiten aktiviert/deaktiviert werden können</li><li><strong>Projekt-Aliase</strong> — automatisch pro Verzeichnis geladen, wie direnv für Aliase</li><li><strong>Parametrisierte Aliase</strong> — Template-Syntax für zusammensetzbare Befehle</li><li><strong>Mehrere aktive Profile</strong> — Aliase mit klarer Priorität schichten</li></ul><h2 id="wo-werden-meine-aliase-gespeichert" tabindex="-1">Wo werden meine Aliase gespeichert? <a class="header-anchor" href="#wo-werden-meine-aliase-gespeichert" aria-label="Permalink to &quot;Wo werden meine Aliase gespeichert?&quot;">​</a></h2><ul><li><strong>Globale und Profil-Aliase:</strong> <code>~/.config/amoxide/config.toml</code></li><li><strong>Projekt-Aliase:</strong> <code>.aliases</code>-Datei im Projektverzeichnis</li></ul><h2 id="kann-ich-amoxide-neben-meinen-bestehenden-shell-aliasen-verwenden" tabindex="-1">Kann ich amoxide neben meinen bestehenden Shell-Aliasen verwenden? <a class="header-anchor" href="#kann-ich-amoxide-neben-meinen-bestehenden-shell-aliasen-verwenden" aria-label="Permalink to &quot;Kann ich amoxide neben meinen bestehenden Shell-Aliasen verwenden?&quot;">​</a></h2><p>Ja. amoxide-Aliase koexistieren mit den nativen Shell-Aliasen. Bei Namenskonflikten hat der amoxide-Alias Vorrang, solange er aktiv ist.</p><h2 id="was-ist-am-tui" tabindex="-1">Was ist <code>am-tui</code>? <a class="header-anchor" href="#was-ist-am-tui" aria-label="Permalink to &quot;Was ist `am-tui`?&quot;">​</a></h2><p>Eine separate Binary (<code>amoxide-tui</code>), die eine interaktive Terminal-Oberfläche zur visuellen Alias-Verwaltung bietet. Nach der Installation integriert sie sich direkt in <code>am</code>:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span></span></code></pre></div><p>Der <code>am tui</code>-Befehl startet das TUI — kein separater Binary-Name nötig. Schnelle Installation:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sassman/tap/amoxide-tui</span></span></code></pre></div><p>Siehe <a href="/_preview/68/de/guide/installation.html#am-tui-installieren">alle Installationsoptionen</a> für Shell-Skript, PowerShell und Cargo.</p><p>:::</p>',17)])])}const u=t(s,[["render",l]]);export{m as __pageData,u as default};
